+        let invocation = try program.resolve(argv: [
+            "peekaboo",
+            "capture",
+            "video",
+            "/tmp/demo.mov",
+            "--sample-fps", "3"
+        ])
+        let values = invocation.parsedValues
+        #expect(values.positional == ["/tmp/demo.mov"])
+        #expect(values.options["sampleFps"] == ["3"])
+    }
